// Build a readable summary for each live fixture
const fixture = $input.item.json;

// Find current score from scores array
const scores = fixture.scores ?? [];
const currentScores = scores.filter(s => s.description === 'CURRENT');

let homeGoals = 0;
let awayGoals = 0;
let homeTeamName = 'Home';
let awayTeamName = 'Away';

const participants = fixture.participants ?? [];
const homeTeam = participants.find(p => p.meta?.location === 'home');
const awayTeam = participants.find(p => p.meta?.location === 'away');

if (homeTeam) homeTeamName = homeTeam.name;
if (awayTeam) awayTeamName = awayTeam.name;

for (const score of currentScores) {
  const participant = participants.find(p => p.id === score.participant_id);
  if (!participant) continue;
  if (participant.meta?.location === 'home') homeGoals = score.score?.goals ?? 0;
  if (participant.meta?.location === 'away') awayGoals = score.score?.goals ?? 0;
}

// Count key events
const events = fixture.events ?? [];
const goals = events.filter(e => e.type?.code === 'goal');
const yellowCards = events.filter(e => e.type?.code === 'yellowcard');
const redCards = events.filter(e => e.type?.code === 'redcard' || e.type?.code === 'yellowredcard');
const substitutions = events.filter(e => e.type?.code === 'substitution');

// Current period
const periods = fixture.periods ?? [];
const activePeriod = periods.find(p => p.ticking === true);
const currentMinute = activePeriod ? activePeriod.minutes : null;

return {
  fixture_id: fixture.id,
  match: fixture.name,
  league: fixture.league?.name ?? 'Unknown',
  country: fixture.league?.country?.name ?? 'Unknown',
  score: `${homeTeamName} ${homeGoals} - ${awayGoals} ${awayTeamName}`,
  home_team: homeTeamName,
  away_team: awayTeamName,
  home_goals: homeGoals,
  away_goals: awayGoals,
  current_minute: currentMinute,
  total_goals: goals.length,
  yellow_cards: yellowCards.length,
  red_cards: redCards.length,
  substitutions: substitutions.length,
  result_info: fixture.result_info,
  starting_at: fixture.starting_at,
  round: fixture.round?.name ? `Round ${fixture.round.name}` : null,
  goal_events: goals.map(g => ({
    minute: g.minute,
    player: g.player_name,
    team: participants.find(p => p.id === g.participant_id)?.name ?? 'Unknown',
    assist: g.related_player_name,
    result: g.result
  }))
};

const matches = $input.item.json.matches ?? [];

if (matches.length === 0) {
  return { summary: 'No live matches at the moment', total_matches: 0 };
}

// Group matches by league
const byLeague = {};
for (const m of matches) {
  const league = m.league ?? 'Unknown';
  if (!byLeague[league]) byLeague[league] = [];
  byLeague[league].push(m.score);
}

const lines = [];
for (const [league, scores] of Object.entries(byLeague)) {
  lines.push(`${league}:`);
  for (const s of scores) lines.push(`  ${s}`);
}

return {
  summary: lines.join('\n'),
  total_matches: matches.length,
  total_goals: matches.reduce((acc, m) => acc + m.total_goals, 0),
  matches
};
